// Simulate wake-sleep library learning
const cycles = [
  {
    phase: 'Initial',
    library: ['move', 'change', 'agent', 'patient', 'object'],
    decomp: '"John gave Mary a book" → move(agent:John, object:book, to:Mary) + change(possessor:book, from:John, to:Mary)',
    cost: 18
  },
  {
    phase: 'Cycle 1 — Wake',
    library: ['move', 'change', 'agent', 'patient', 'object'],
    decomp: 'Decompose 500 event sentences using current primitives...',
    cost: 18
  },
  {
    phase: 'Cycle 1 — Sleep-Abstract',
    library: ['move', 'change', 'agent', 'patient', 'object', 'TRANSFER'],
    decomp: 'Found: move+change(possession) recurs 89 times → abstract as TRANSFER',
    cost: 12
  },
  {
    phase: 'Cycle 2 — Sleep-Abstract',
    library: ['move', 'change', 'TRANSFER', 'PROPEL', 'INFORM', 'STATE_Δ'],
    decomp: '"John gave Mary a book" → TRANSFER(John, book, Mary)',
    cost: 5
  },
  {
    phase: 'Cycle 3 — Converged',
    library: ['ATRANS', 'PTRANS', 'MTRANS', 'PROPEL', 'MBUILD', 'ATTEND', 'SPEAK', 'INGEST', 'EXPEL', 'GRASP', 'MOVE', 'STATE_Δ'],
    decomp: '"John gave Mary a book" → ATRANS(John, book, Mary)',
    cost: 3
  }
];

let html = '<div style="font-family:monospace;font-size:12px">';
cycles.forEach((c, i) => {
  const color = i === cycles.length-1 ? '#4ade80' : '#60a5fa';
  html += `<div style="margin-bottom:12px;border-left:3px solid ${color};padding-left:10px">`;
  html += `<b style="color:${color}">${c.phase}</b><br>`;
  html += `<span style="color:#fbbf24">Library (${c.library.length}):</span> ${c.library.join(', ')}<br>`;
  html += `<span style="color:#a78bfa">${c.decomp}</span><br>`;
  html += `<span style="color:#888">Description cost: ${c.cost} tokens</span>`;
  html += '</div>';
});
html += '<div style="color:#4ade80;margin-top:8px">✨ Primitives EMERGED — not programmed! Cost: 18 → 3 tokens</div>';
html += '</div>';
return html;

// Visualize the MDL trade-off
const librarySizes = [1, 3, 5, 8, 11, 14, 20, 30, 50, 100, 500];
const libCostPerPrimitive = 3;
const totalEvents = 1000;

function avgDecompCost(k) {
  // Rough model: more primitives = shorter decompositions
  return 10 * Math.pow(k, -0.5) + 1;
}

let html = '<div style="font-family:monospace;font-size:12px">';
html += '<b>MDL Cost vs Library Size:</b><br><br>';
html += '<table style="border-collapse:collapse">';
html += '<tr style="color:#fbbf24;border-bottom:1px solid #444"><td style="padding:3px 8px">|L|</td><td style="padding:3px 8px">Lib Cost</td><td style="padding:3px 8px">Avg Decomp</td><td style="padding:3px 8px">Total MDL</td><td style="padding:3px 8px">Bar</td></tr>';

let minCost = Infinity, minK = 0;
librarySizes.forEach(k => {
  const lc = k * libCostPerPrimitive;
  const dc = avgDecompCost(k);
  const total = lc + totalEvents * dc;
  if (total < minCost) { minCost = total; minK = k; }
});

librarySizes.forEach(k => {
  const lc = k * libCostPerPrimitive;
  const dc = avgDecompCost(k);
  const total = lc + totalEvents * dc;
  const barLen = Math.round(total / 200);
  const isMin = k === minK;
  const color = isMin ? '#4ade80' : '#60a5fa';
  const bg = isMin ? 'background:#1a3a1a;' : '';
  html += `<tr style="${bg}">`;
  html += `<td style="padding:3px 8px;color:${color}">${k}</td>`;
  html += `<td style="padding:3px 8px">${lc}</td>`;
  html += `<td style="padding:3px 8px">${dc.toFixed(1)}</td>`;
  html += `<td style="padding:3px 8px;color:${color}">${total.toFixed(0)}</td>`;
  html += `<td style="padding:3px 8px"><span style="background:${color};display:inline-block;height:10px;width:${Math.min(barLen,40)}px;border-radius:2px"></span></td>`;
  html += '</tr>';
});
html += '</table><br>';
html += `<span style="color:#4ade80">✨ MDL optimum: ~${minK} primitives — right in Schank's range!</span></div>`;
return html;

const phases = [
  {
    name: '🌅 WAKE Phase',
    color: '#fbbf24',
    what: 'Decompose event sentences using current operator library',
    how: 'Neural search guided by recognition model (trained in dreaming phase)',
    input: '"The thief stole the diamond from the museum"',
    output: 'ATRANS(thief, diamond, museum→thief) + PTRANS(thief+diamond, museum→outside)',
    purpose: 'Generate decomposition data for abstraction'
  },
  {
    name: '🌙 SLEEP-ABSTRACTION',
    color: '#a78bfa',
    what: 'Compress recurring sub-expressions into new library entries',
    how: 'Stitch algorithm finds max-compression abstractions across all decompositions',
    input: 'Corpus of 500 decompositions from wake phase',
    output: 'New operator: STEAL = ATRANS(agent, obj, victim→agent) [anti-social, covert]',
    purpose: 'Grow the library — discover new primitives'
  },
  {
    name: '💤 SLEEP-DREAMING',
    color: '#60a5fa',
    what: 'Generate synthetic event sentences to train the recognition model',
    how: 'Sample operator expressions from library, use LLM to generate natural language',
    input: 'Library: {ATRANS, PTRANS, MTRANS, PROPEL, ...}',
    output: '"The teacher explained gravity" → MTRANS(teacher, knowledge, students)',
    purpose: 'Improve wake-phase search — amortized inference'
  }
];

let html = '<div style="font-family:monospace;font-size:12px">';
phases.forEach(p => {
  html += `<div style="margin-bottom:14px;border-left:3px solid ${p.color};padding-left:10px">`;
  html += `<b style="color:${p.color}">${p.name}</b><br>`;
  html += `<b>What:</b> ${p.what}<br>`;
  html += `<b>How:</b> ${p.how}<br>`;
  html += `<span style="color:#888">Input:</span> <i>${p.input}</i><br>`;
  html += `<span style="color:#888">Output:</span> <i>${p.output}</i><br>`;
  html += `<span style="color:#4ade80">Purpose:</span> ${p.purpose}`;
  html += '</div>';
});
html += '<div style="color:#fbbf24;text-align:center">↻ Repeat until library converges (typically 5-10 cycles)</div>';
html += '</div>';
return html;

const components = [
  { name: 'Event Corpus', x: 10, y: 20, w: 120, color: '#60a5fa', desc: 'VerbNet + ATOMIC' },
  { name: 'Event Parser', x: 10, y: 80, w: 120, color: '#fbbf24', desc: 'LLM → SVO triples' },
  { name: 'Decomposer', x: 10, y: 140, w: 120, color: '#f87171', desc: 'Search w/ library' },
  { name: 'Operator Library', x: 160, y: 110, w: 140, color: '#4ade80', desc: 'Growing primitive set' },
  { name: 'Stitch', x: 160, y: 180, w: 140, color: '#a78bfa', desc: 'Compress → abstract' },
  { name: 'Dreamer', x: 320, y: 110, w: 120, color: '#818cf8', desc: 'Generate synthetics' },
  { name: 'Recognition NN', x: 320, y: 180, w: 120, color: '#fb923c', desc: 'Amortize search' },
  { name: 'LLM Documenter', x: 160, y: 250, w: 140, color: '#2dd4bf', desc: 'Name & explain' },
];

let html = '<div style="font-family:monospace;font-size:11px;position:relative;height:310px;background:#0f1219;border-radius:8px;padding:8px">';
components.forEach(c => {
  html += `<div style="position:absolute;left:${c.x}px;top:${c.y}px;width:${c.w}px;`;
  html += `background:${c.color}22;border:1px solid ${c.color};border-radius:6px;padding:6px;text-align:center">`;
  html += `<b style="color:${c.color}">${c.name}</b><br>`;
  html += `<span style="color:#888;font-size:10px">${c.desc}</span></div>`;
});

// Arrows as text
html += '<div style="position:absolute;left:70px;top:60px;color:#666">↓</div>';
html += '<div style="position:absolute;left:70px;top:120px;color:#666">↓</div>';
html += '<div style="position:absolute;left:135px;top:130px;color:#4ade80">→</div>';
html += '<div style="position:absolute;left:230px;top:165px;color:#a78bfa">↓ abstract</div>';
html += '<div style="position:absolute;left:305px;top:130px;color:#818cf8">←</div>';
html += '<div style="position:absolute;left:380px;top:165px;color:#fb923c">↓ train</div>';
html += '<div style="position:absolute;left:230px;top:232px;color:#2dd4bf">↓ name</div>';
html += '<div style="position:absolute;left:160px;top:295px;color:#4ade80;font-size:10px">↻ Repeat wake-sleep cycles</div>';
html += '</div>';
return html;
